-- Part 1: University-level data for Leiden University
UPDATE public.universities SET
  website_url = 'https://www.universiteitleiden.nl/en/education/study-programmes/bachelor',
  tuition_usd = 15587,
  overall_acceptance_rate = '~63%',
  test_policy = 'Not applicable',
  deadline_calendar = 'Non-EEA students requiring visa/residence permit: 1 May 2025 (bachelor programs); Early Bird Non-EEA: 1 December 2024; Numerus fixus programs (Psychology, Political Science: IR&O): 15 January 2025; Regular deadline: 15 March 2025. Application fee: EUR 100 (non-refundable, covers up to 3 programs). Application via Studielink (national portal) then Leiden uSis portal.',
  financial_aid = 'NL Scholarship (Holland Scholarship): EUR 5,000 one-time award for non-EEA students enrolling in English-taught bachelor programs starting September 2025 (eligibility via studyinnl.org). Leiden Excellence Scholarship (LExS): partial to full tuition fee award for outstanding non-EEA master candidates. Huygens Scholarship Programme (Dutch government): covers tuition + living costs for exceptional non-EEA students. Leiden University Fund (LUF) scholarships: various merit and need-based awards. Low statutory tuition for EEA nationals: EUR 2,694/yr (2026-2027). Non-EEA institutional tuition: EUR 14,300/yr for most faculties; EUR 18,700/yr for Biomedical Sciences/Medicine; EUR 17,570/yr for LUC The Hague. Blocked account (~EUR 12,000-13,000/yr) required for non-EEA student visa application.'
WHERE name = 'Leiden University';

-- Part 2: Top 10 English-taught bachelor majors for Leiden University
INSERT INTO public.majors (university_id, major_name, acceptance_rate, supplemental_requirements, subject_ranking, ielts_min, toefl_min, sat_min, act_min, gpa_min, a_level_grades, ib_min, atar_min, duolingo_min, pte_min)
