  ('English Language and Culture (BA)', NULL, 'English-taught; covers linguistics, literature, and cultural analysis in the English-speaking world; strong interest in literary analysis and language study required; diploma equivalent to Dutch VWO; IELTS 6.5 overall minimum 6.0 per component; non-EEA deadline 1 May; programme based at Leiden campus; regular deadline 15 March; Leiden ranks QS Top 150 World (Linguistics)', NULL, 6.5, 90, NULL, NULL, NULL, 'BBB', 29, NULL, NULL, 58),
